module serial2parallel(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0] dout_parallel,
    output reg dout_valid
);

reg [2:0] count;
reg [7:0] shift_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        count <= 3'b000;
        shift_reg <= 8'b0;
        dout_parallel <= 8'b0;
        dout_valid <= 1'b0;
    end else begin
        if (din_valid) begin
            shift_reg <= {shift_reg[6:0], din_serial};
            count <= count + 1'b1;
            if (count == 3'b111) begin
                dout_parallel <= shift_reg;
                dout_valid <= 1'b1;
            end else begin
                dout_valid <= 1'b0;
            end
        end else begin
            dout_valid <= 1'b0;
        end
    end
end

endmodule
